<style>.btn{border-radius:5px;width:auto;font-size:18px;padding:8px 30px;font-weight:400;text-decoration:none}.btn:hover{text-decoration:none}.btn-primary{background:#ec1e28;color:#fff;border:1px solid #ec1e28;-webkit-transition:all 1s ease;-moz-transition:all 1s ease;transition:all 1s ease}.btn-primary:hover{background:#fff;color:#ec1e28}.btn-secondary{background:0 0;color:#ec1e28;border:1px solid #ec1e28;-webkit-transition:all 1s ease;-moz-transition:all 1s ease;transition:all 1s ease}.btn-secondary:hover{background:#ec1e28;color:#fff;border:1px solid #ec1e28}.btn-blue{background:#24345f;color:#fff;border:1px solid #24345f;-webkit-transition:all 1s ease;-moz-transition:all 1s ease;transition:all 1s ease}.btn-blue:hover{color:#24345f;background:#fff}.btn-red{background:#fff6f6;color:#ec1e28;border:1px solid #fff6f6;-webkit-transition:all 1s ease;-moz-transition:all 1s ease;transition:all 1s ease}.btn-red:hover{border:1px solid #ec1e28;background:#ec1e28;color:#fff6f6}.btn-blue-invert{background:#fff;color:#24345f;border:1px solid #24345f}.btn-blue-invert:hover{background:#24345f;color:#fff}.btn-gray{background:#f1f2f4;color:#000;border:1px solid #f1f2f4}.btn-gray:hover{background:#fff;color:#000}</style>